 70	void generate_mch(PHY_VARS_eNB *eNB,L1_rxtx_proc_t *proc,uint8_t *a)
 71	{
 72	
 73	  int G;
 74	  int subframe = proc->subframe_tx;
 75	  int frame    = proc->frame_tx;
 76	
 77	  G = get_G(&eNB->frame_parms,
 78		    eNB->frame_parms.N_RB_DL,
 79		    eNB->dlsch_MCH->harq_processes[0]->rb_alloc,
 80		    get_Qm(eNB->dlsch_MCH->harq_processes[0]->mcs),1,
 81		    2,proc->frame_tx,subframe,0);
 82	  
 83	  eNB->dlsch_MCH->harq_processes[0]->Qm = get_Qm(eNB->dlsch_MCH->harq_processes[0]->mcs);
 84	 
 85	  generate_mbsfn_pilot(eNB,proc,
 86			       eNB->common_vars.txdataF,
 87			       AMP);
 88	  
 89	  AssertFatal(eNB->dlsch_MCH->harq_processes[0]->pdu != NULL, "attempt to encode a NULL harq PDU\n");
 90	  
 91	  AssertFatal(dlsch_encoding(eNB,
 92				     proc,
 93				    // a,
 94				    eNB->dlsch_MCH->harq_processes[0]->pdu,
 95				     1,
 96				     eNB->dlsch_MCH,
 97				     proc->frame_tx,
 98				     subframe,
 99				     &eNB->dlsch_rate_matching_stats,
100				     &eNB->dlsch_turbo_encoding_stats,
101				     &eNB->dlsch_interleaving_stats)==0,
102		      "problem in dlsch_encoding");
103	  
104	  dlsch_scrambling(&eNB->frame_parms,1,eNB->dlsch_MCH,0,G,0,frame,subframe<<1);
105	  
106	  
107	  mch_modulation(eNB->common_vars.txdataF,
108			 AMP,
109			 subframe,
110			 &eNB->frame_parms,
111			 eNB->dlsch_MCH);
112	
113	}
