115	void generate_mch_khz_1dot25(PHY_VARS_eNB *eNB,L1_rxtx_proc_t *proc,uint8_t *a)
116	{
117	
118	  int G;
119	  int subframe = proc->subframe_tx;
120	  int frame    = proc->frame_tx;
121	  //int bits;
122	
123	  G = get_G_khz_1dot25(&eNB->frame_parms,
124	            eNB->frame_parms.N_RB_DL,
125	            eNB->dlsch_MCH->harq_processes[0]->rb_alloc,
126	            get_Qm(eNB->dlsch_MCH->harq_processes[0]->mcs),1,
127	            2,proc->frame_tx,subframe,0);
128	
129	  //FeMBMS
130	  eNB->dlsch_MCH->harq_processes[0]->Qm = get_Qm(eNB->dlsch_MCH->harq_processes[0]->mcs);
131	
132	
133	  generate_mbsfn_pilot_khz_1dot25(eNB,proc,
134	                       eNB->common_vars.txdataF,
135	                       AMP);
136	
137	
138	  AssertFatal(dlsch_encoding_fembms_pmch(eNB,
139				    proc,
140	                            // a,
141				     eNB->dlsch_MCH->harq_processes[0]->pdu,
142	                             1,
143	                             eNB->dlsch_MCH,
144	                             proc->frame_tx,
145	                             subframe,
146	                             &eNB->dlsch_rate_matching_stats,
147	                             &eNB->dlsch_turbo_encoding_stats,
148	                             &eNB->dlsch_interleaving_stats)==0,
149	              "problem in dlsch_encoding");
150	
151	
152	  /*for(bits=0;bits<G;bits++)
153	        printf("%d",eNB->dlsch_MCH->harq_processes[0]->e[bits]);
154	  printf("\n");*/
155	
156	  dlsch_scrambling(&eNB->frame_parms,1,eNB->dlsch_MCH,0,G,0,frame,subframe<<1);
157	
158	  mch_modulation_khz_1dot25(eNB->common_vars.txdataF,
159	                 AMP,
160	                 subframe,
161	                 &eNB->frame_parms,
162	                 eNB->dlsch_MCH);
163	}
